    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        return self.custom_matmul(A, B)

    def custom_matmul(self, A: torch.Tensor, B: torch.Tensor) -> torch.Tensor:
        # Assuming A and B are both on the GPU
        assert A.device.type == 'cuda' and B.device.type == 'cuda'

        M, K = A.shape
        K, N = B.shape

        # Allocate output tensor on the same device as A and B
        C = torch.empty((M, N), dtype=A.dtype, device=A.device)

        # Define the CUDA kernel
        kernel_code = """
        extern "C" __global__
        void custom_matmul_kernel(const float* A, const float* B, float* C, int M, int K, int N) {
            int row = blockIdx.y * blockDim.y + threadIdx.y;
            int col = blockIdx.x * blockDim.x + threadIdx.x;

            if (row < M && col < N) {
                float sum = 0.0f;
                for (int k = 0; k < K; ++k) {
                    sum += A[row * K + k] * B[k * N + col];
                }
                C[row * N + col] = sum;
            }
        }
        """

        # Compile and load the kernel
        custom_matmul_module = load_inline(
            name="custom_matmul_module",
            cpp_sources=[],
