namespace {

__global__ void fused_conv_bias_activation(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int N, int IC, int ID, int IH, int IW, int OC, int KD, int KH, int KW) {

    const int n = blockIdx.z;
    const int oc = blockIdx.y * blockDim.y + threadIdx.y;
    const int ic = blockIdx.x * blockDim.x + threadIdx.x;

    if (oc >= OC || ic >= IC) return;

    float accum[16] = {0};
    for (int kd = 0; kd < KD; ++kd) {
        for (int kh = 0; kh < KH; ++kh) {
            for (int kw = 0; kw < KW; ++kw) {
                const int id = n * ID * IH * IW + (threadIdx.z * ID + kd) * IH * IW + (threadIdx.y * IH + kh) * IW + (threadIdx.x * IW + kw);
                const int ic_idx = ic * IC * ID * IH * IW + id;
                const int weight_idx = oc * OC * IC * KD * KH * KW + (kd * IC + ic) * KH * KW + (kh * KW + kw);
                accum[threadIdx.z & 0xF] += input[ic_idx] * weight[weight_idx];
