    __syncthreads();

    if (threadIdx.z == 0) {
        const int output_idx = n * OC * ID * IH * IW + (oc * ID + blockIdx.z) * IH * IW + (blockIdx.y * IH + blockIdx.y) * IW + (blockIdx.x * IW + blockIdx.x);
        output[output_idx] = accum[0] + bias[oc];
        output[output_idx] = fmaxf(output[output_idx], 0.0f); // ReLU
