#include <torch/torch.h>

void bias_relu_forward(const torch::Tensor& input, const torch::Tensor& bias, torch::Tensor& output) {
    auto input_data = input.data_ptr<float>();
    auto bias_data = bias.data_ptr<float>();
    auto output_data = output.data_ptr<float>();

    const int batch_size = input.size(0);
    const int size = input.size(1);

    #pragma omp parallel for collapse(2)
    for (int b = 0; b < batch_size; ++b) {
        for (int i = 0; i < size; ++i) {
            output_data[b * size + i] = std::max(input_data[b * size + i] + bias_data[i], 0.0f);
